"use strict";(globalThis.webpackChunkgsf_docusaurus_template=globalThis.webpackChunkgsf_docusaurus_template||[]).push([[3339],{8897(e){e.exports=JSON.parse('{"tag":{"label":"persona:devops-engineer","permalink":"/tags/persona-devops-engineer","allTagsPath":"/tags","count":35,"items":[{"id":"catalog/architecture/system-topology/serverless-model-development","title":"Adopt serverless architecture for AI/ML workload processes","description":"Building an ML model takes significant computing resources that need to be optimized for efficient utilization.","permalink":"/catalog/architecture/system-topology/serverless-model-development"},{"id":"catalog/architecture/system-topology/choose-region-closest-to-users","title":"Choose the region that is closest to users","description":"From an energy-efficiency perspective, it\'s better to shorten the distance a network packet travels so that less energy is required to transmit it. Similarly, from an embodied-carbon perspective, when a network packet traverses through less computing equipment, we are more efficient with hardware.","permalink":"/catalog/architecture/system-topology/choose-region-closest-to-users"},{"id":"catalog/development/data-handling/compress-stored-data","title":"Compress stored data","description":"Description","permalink":"/catalog/development/data-handling/compress-stored-data"},{"id":"catalog/development/data-handling/compress-transmitted-data","title":"Compress transmitted data","description":"From an energy-efficiency perspective, it\'s better to minimise the size of the data transmitted so that less energy is required because the network traffic is reduced.","permalink":"/catalog/development/data-handling/compress-transmitted-data"},{"id":"catalog/architecture/system-topology/containerize-your-workload-where-applicable","title":"Containerize your workloads","description":"Description","permalink":"/catalog/architecture/system-topology/containerize-your-workload-where-applicable"},{"id":"catalog/operations/resource-lifecycle/delete-unused-storage-resources","title":"Delete unused storage resources","description":"From an embodied carbon perspective, it\'s better to delete unused storage resources so we are efficient with hardware and so that the storage layer is optimised for the task.","permalink":"/catalog/operations/resource-lifecycle/delete-unused-storage-resources"},{"id":"catalog/development/web-performance/enable-text-compression","title":"Enable text compression","description":"Web browsers often communicate with web servers in a human readable format. These can be HTML, JavaScript and/or CSS files and REST requests which can return a response in JSON. This human readable communication is redundant and, as such, can be compressed to save bandwidth.","permalink":"/catalog/development/web-performance/enable-text-compression"},{"id":"catalog/requirements/encrypt-what-is-necessary","title":"Encrypt what is necessary","description":"Data protection through encryption is a crucial aspect of our security measures. However, the encryption process can be resource-intensive at multiple levels.","permalink":"/catalog/requirements/encrypt-what-is-necessary"},{"id":"catalog/architecture/technology-selection/evaluate-other-cpu-architectures","title":"Evaluate other CPU architectures","description":"Applications are built with a software architecture that best fits the business need they are serving. Cloud providers make it easy to evaluate other CPU types","permalink":"/catalog/architecture/technology-selection/evaluate-other-cpu-architectures"},{"id":"catalog/architecture/system-topology/implement-stateless-design","title":"Implement stateless design","description":"Service state refers to the in-memory or on-disk data required by a service to function. State includes the data structures and member variables that the service reads and writes. Depending on how the service is architected, the state might also include files or other resources stored on the disk. Applications that consume large memory or on-disk data require larger VM sizes, especially for cloud computing where you would need larger VM SKUs to support high RAM capacity and multiple data disks.","permalink":"/catalog/architecture/system-topology/implement-stateless-design"},{"id":"catalog/operations/capacity-management/match-utilization-requirements-of-vm","title":"Match utilization requirements of virtual machines (VMs)","description":"It\'s better to have one VM running at a higher utilization than two running at low utilization rates, not only in terms of energy proportionality but also in terms of embodied carbon. Two servers running at low utilization rates will consume more energy than one running at a high utilization rate. In addition, the unused capacity on the underutilized server could be more efficiently used for another task or process.","permalink":"/catalog/operations/capacity-management/match-utilization-requirements-of-vm"},{"id":"catalog/operations/capacity-management/match-utilization-requirements-with-pre-configured-server","title":"Match utilization requirements with pre-configured servers","description":"It\'s better to have one VM running at a higher utilization than two running at low utilization rates, not only in terms of energy proportionality but also in terms of embodied carbon. Two servers running at low utilization rates will consume more energy than one running at a high utilization rate. In addition, the unused capacity on the underutilized server could be more efficiently used for another task or process.","permalink":"/catalog/operations/capacity-management/match-utilization-requirements-with-pre-configured-server"},{"id":"catalog/requirements/match-slo","title":"Match your service level objectives to business needs","description":"If service downtimes are acceptable it\'s better to not strive for highest availability but to design the solution according to real business needs. Lower availability guarantees can help reduce energy consumption by using less infrastructure components.","permalink":"/catalog/requirements/match-slo"},{"id":"catalog/development/minimizing-deployed-environments","title":"Minimize the total number of deployed environments","description":"In a given application, there may be a need to utilize multiple environments in the application workflow. Typically, a development environment is used for regular updates, while staging or testing enviroments are used to make sure there are no issues before code reaches a production environment where users may have access. Each added environment has an increasing energy impact, which in turn creates more emissions. As such, it is important to understand the necessity of each enviroment and it\'s environmental impact.","permalink":"/catalog/development/minimizing-deployed-environments"},{"id":"catalog/operations/resource-lifecycle/optimise-storage-resource-utilisation","title":"Optimise storage utilization","description":"It\'s better to maximise storage utilisation so the storage layer is optimised for the task, not only in terms of energy proportionality but also in terms of embodied carbon. Two storage units running at low utilization rates will consume more energy than one running at a high utilization rate. In addition, the unused capacity on the underutilised storage unit could be more efficiently used for another task or process.","permalink":"/catalog/operations/resource-lifecycle/optimise-storage-resource-utilisation"},{"id":"catalog/operations/capacity-management/optimize-avg-cpu-utilization","title":"Optimize average CPU utilization","description":"CPU usage and utilization varies throughout the day, sometimes wildly for different computational requirements. The larger the variance between the average and peak CPU utilization values, the more resources need to be provisioned in stand-by mode to absorb those spikes in traffic.","permalink":"/catalog/operations/capacity-management/optimize-avg-cpu-utilization"},{"id":"catalog/operations/capacity-management/optimize-peak-cpu-utilization","title":"Optimize peak CPU utilization","description":"CPU usage and utilization varies throughout the day, sometimes wildly for different computational requirements. The larger the variance between the average and peak CPU utilization values, the more resources need to be provisioned in stand-by mode to absorb those spikes in traffic.","permalink":"/catalog/operations/capacity-management/optimize-peak-cpu-utilization"},{"id":"catalog/architecture/system-topology/queue-non-urgent-requests","title":"Queue non-urgent processing requests","description":"All systems have periods of peak and low load. From a hardware-efficiency perspective, we are more efficient with hardware if we minimise the impact of request spikes with an implementation that allows an even utilization of components. From an energy-efficiency perspective, we are more efficient with energy if we ensure that idle resources are kept to a minimum.","permalink":"/catalog/architecture/system-topology/queue-non-urgent-requests"},{"id":"catalog/architecture/system-topology/reduce-network-traversal-between-VMs","title":"Reduce network traversal between VMs","description":"Description","permalink":"/catalog/architecture/system-topology/reduce-network-traversal-between-VMs"},{"id":"catalog/operations/resource-lifecycle/remove-unused-assets","title":"Remove unused assets","description":"Description","permalink":"/catalog/operations/resource-lifecycle/remove-unused-assets"},{"id":"catalog/architecture/system-topology/energy-efficent-ai-edge","title":"Run AI models at the edge","description":"Data computation for ML workloads and ML inference is a significant contributor to the carbon footprint of the ML application. Also, if the ML model is running on the cloud, the data needs to be transferred and processed on the cloud to the required format that can be used by the ML model for inference.","permalink":"/catalog/architecture/system-topology/energy-efficent-ai-edge"},{"id":"catalog/operations/capacity-management/scale-down-unused-applications","title":"Scale down applications when not in use","description":"Applications consume CPU even when they are not actively in use. For example, background timers, garbage collection, health checks, etc. Even when the application is shut down, the underlying hardware is consuming idle power.","permalink":"/catalog/operations/capacity-management/scale-down-unused-applications"},{"id":"catalog/operations/capacity-management/scale-down-kubernetes-workloads","title":"Scale down kubernetes applications when not in use","description":"In order to reduce carbon emissions and costs, Dev&Test Kubernetes clusters can turn off nodes out of office hours. Thereby, optimization is implemented at the cluster level. For production clusters, where nodes need to stay up and running, optimization needs to be implemented at the application level.","permalink":"/catalog/operations/capacity-management/scale-down-kubernetes-workloads"},{"id":"catalog/operations/capacity-management/scale-infrastructure-with-user-load","title":"Scale infrastructure with user load","description":"Demand for resources depends on user load at any given time. However, most applications run without taking this into consideration. As a result,resources are underused and inefficient.","permalink":"/catalog/operations/capacity-management/scale-infrastructure-with-user-load"},{"id":"catalog/operations/capacity-management/scale-kubernetes-workloads-based-on-events","title":"Scale Kubernetes workloads based on relevant demand metrics","description":"By default, Kubernetes scales workloads based on CPU and RAM utilization. In practice, however, it\'s difficult to correlate your application\'s demand drivers with CPU and RAM utilization. Scaling your workload based on relevant demand metrics that drive scaling of your applications, such as HTTP requests, queue length, and cloud alerting events can help reduce resource utilization, and therefore also your carbon emissions.","permalink":"/catalog/operations/capacity-management/scale-kubernetes-workloads-based-on-events"},{"id":"catalog/architecture/system-topology/scale-logical-components-independently","title":"Scale logical components independently","description":"Description","permalink":"/catalog/architecture/system-topology/scale-logical-components-independently"},{"id":"catalog/architecture/technology-selection/right-hardware-type","title":"Select the right hardware/VM instance types for AI/ML training","description":"Selecting the right hardware/VM instance types for training is one of the choices you should make as part of your energy-efficient AI/ML process.","permalink":"/catalog/architecture/technology-selection/right-hardware-type"},{"id":"catalog/operations/resource-lifecycle/set-retention-policy-on-storage-resources","title":"Set storage retention policies","description":"From an embodied carbon perspective, it\'s better to have an automated mechanism to delete unused storage resources so we are efficient with hardware and so that the storage layer is optimised for the task.","permalink":"/catalog/operations/resource-lifecycle/set-retention-policy-on-storage-resources"},{"id":"catalog/requirements/shed-lower-priority-traffic","title":"Shed lower priority traffic","description":"When resources are constrained during high-traffic events or when carbon intensity is high, more carbon emissions will be generated from your system. Adding more resources to support increased traffic requirements introduces more embodied carbon and more demand for electricity. Continuing to handle all requests during high carbon intensity will increase overall emissions for your system. Shedding traffic that is lower priority during these scenarios will save on resources and carbon emissions. This approach requires an understanding of your traffic, including which call requests are critical and which can best withstand retry attempts and failures.","permalink":"/catalog/requirements/shed-lower-priority-traffic"},{"id":"catalog/development/evaluate-whether-to-use-TLS-termination","title":"Terminate TLS at border gateway","description":"Transport Layer Security (TLS) ensures that all data passed between the web server and web browsers remain private and encrypted. However, terminating and re-establishing TLS increases CPU usage and might be unnecessary in certain architectures.","permalink":"/catalog/development/evaluate-whether-to-use-TLS-termination"},{"id":"catalog/operations/time-shift-kubernetes-cron-jobs","title":"Time-shift Kubernetes cron jobs","description":"The carbon emissions of a software system depends on the power consumed by that software, but also on the Carbon intensity of the electricity it is powered on. For this reason, running energy-efficient software on carbon intensive electricity grid, might be inefficient to reduce its global carbon emissions. Carbon aware time scheduling, is about scheduling workloads to execute, when electricity carbon intensity is low.","permalink":"/catalog/operations/time-shift-kubernetes-cron-jobs"},{"id":"catalog/architecture/system-topology/evaluate-using-a-service-mesh","title":"Use a service mesh only if needed","description":"Description","permalink":"/catalog/architecture/system-topology/evaluate-using-a-service-mesh"},{"id":"catalog/operations/capacity-management/use-circuit-breaker","title":"Use circuit breaker patterns","description":"Modern applications need to communicate with other applications on a regular basis. Since these other applications have their own deployment schedule, downtimes and availability, the network connection to these application might have problems. If the other application is not reachable, all network requests against this other application will fail and future network requests are futile.","permalink":"/catalog/operations/capacity-management/use-circuit-breaker"},{"id":"catalog/architecture/technology-selection/use-energy-efficient-hardware","title":"Use cloud native processor VMs","description":"Description","permalink":"/catalog/architecture/technology-selection/use-energy-efficient-hardware"},{"id":"catalog/architecture/technology-selection/use-serverless","title":"Use serverless cloud services","description":"Description","permalink":"/catalog/architecture/technology-selection/use-serverless"}],"unlisted":false}}')}}]);